int countPrimes(int n) {
    if (n <= 2) return 0;
    char* sieve = calloc(n, 1);
    sieve[0] = sieve[1] = 1;
    int cnt = 0;
    for (int i = 2; i * i < n; i++)
        if (!sieve[i])
            for (int j = i * i; j < n; j += i)
                sieve[j] = 1;
    for (int i = 2; i < n; i++) if (!sieve[i]) cnt++;
    free(sieve);
    return cnt;
}
